function formatStatusForBadge(s) { if (!s) return "Em trânsito"; return s.split(" - ")[0].trim(); }

function getEventIconInfo(status) {
  const u = (status || "").toUpperCase();
  if (u.includes("SUPERFRETE") || u.includes("MONITORAMENTO")) return { icon: "userRound", flip: false };
  if (isIncidenteInternoStatus(status)) return { icon: "alertTriangle", flip: false };
  if (isSinistroStatus(status) || isParadoStatus(status) || isEnderecoIncorretoStatus(status)) return { icon: "alertTriangle", flip: false };
  if (isExtravioStatus(status) || isAvariaStatus(status)) return { icon: "xCircle", flip: false };
  if (isRefusedStatus(status)) return { icon: "xCircle", flip: false };
  if (u === "CANCELADA" || u.includes("CANCELADA") || u.includes("CANCELADO")) return { icon: "xCircle", flip: false };
  if (isInReturnStatus(status)) return { icon: "truck", flip: true };
  if (u === "DEVOLVIDO" || u.includes("DEVOLVIDO")) return { icon: "truck", flip: true };
  if (u.includes("ENTREGUE")) return { icon: "checkCircle2", flip: false };
  if (u.includes("POSTADO") || u.includes("POSTAGEM")) return { icon: "package", flip: false };
  if (u.includes("EMISSÃO") || u.includes("EMISSAO") || u.includes("ETIQUETA")) return { icon: "fileText", flip: false };
  return { icon: "truck", flip: false };
}

// ============================================================================
// Helper: extract first event date as YYYY-MM-DD
// ============================================================================

function firstEventDateOnly(eventos) {
  if (!eventos || !eventos.length) return undefined;
  const d = eventos[0].data;
  if (!d) return undefined;
  return d.split(" ")[0];
}

/** Find the date when "Problema Endereço" first appeared — scan all events, return the oldest */
function getProblemaEnderecoEventDate(eventos) {
  if (!eventos || !eventos.length) return undefined;
  const matching = eventos.filter(e => {
    const s = (e.status || "").toUpperCase();
    const d = (e.descricao || "").toUpperCase();
    const combined = s + " " + d;
    return combined.includes("PROBLEMA") && (combined.includes("ENDERE") || combined.includes("ENDERECO") || combined.includes("DESTINAT")) ||
      isEnderecoIncorretoStatus(e.status) || isEnderecoIncorretoStatus(e.descricao);
  });
  const dates = matching.map(e => e.data?.split(" ")[0]).filter(d => d && /^\d{4}-\d{2}-\d{2}$/.test(d));
  if (!dates.length) return undefined;
  return dates.reduce((oldest, d) => d < oldest ? d : oldest);
}

